def group_anagrams(titles):
    anagram_groups = []

    for title in titles:
        sorted_title = ''.join(sorted(title))
        found_group = False

        for group in anagram_groups:
            if sorted_title == ''.join(sorted(group[0])):  
                group.append(title)  
                found_group = True
                break
        if not found_group:
            anagram_groups.append([title])

    return anagram_groups

input_titles = input().split()
result = group_anagrams(input_titles)
for i in result:
    print(i)
